  const response = await this.helpers.httpRequest({ method: 'POST', url: 'https://helpful-spoonbill-863.convex.site/n8n/state', headers: { 'Content-Type': 'application/json', 'x-wafachat-adapter-secret': 'f_ILXhpK1otsmumBuAHZcalOQkX8jXSwSQVYqvjaiew' }, body, json: true });
  return [{ json: response }];
} catch (error) {
  return [{ json: { success: false, error: error.message || 'convex adapter request failed', _action: body.action || null } }];
