const state = $getWorkflowStaticData('global');
const globalEnabled = state.global_ai_enabled !== false;
const phones = state.phone_index || Object.keys(state).filter(k => k !== '__global__' && k !== 'phone_index' && k !== 'daily_stats' && k !== 'global_ai_enabled');
const customers = phones.map(phone => { const data = state[phone]; if (!data || typeof data !== 'object') return null; return { phone, status: data.status || 'active', customerName: data.customerName || '', productName: data.productName || '', csName: data.csName || '', note: data.note || '', updatedAt: data.updatedAt || data.updated_at || null }; }).filter(c => c && c.status !== 'closed');
customers.sort((a, b) => { if (a.status === 'handover' && b.status !== 'handover') return -1; if (a.status !== 'handover' && b.status === 'handover') return 1; return a.phone.localeCompare(b.phone); });
const today = new Date().toISOString().split('T')[0];
const todayStats = (state.daily_stats || {})[today] || { orders: 0, closings: 0, handovers: 0, closed_today: 0 };
return [{ json: { generated_at: new Date().toISOString(), global_ai_enabled: globalEnabled, active_count: customers.filter(c => c.status === 'active').length, handover_count: customers.filter(c => c.status === 'handover').length, total_active: customers.length, stats: todayStats, customers } }];
